noncompliant:
// Noncompliant: Anonymous authentication
var entry = new DirectoryEntry("LDAP://myserver");
entry.AuthenticationType = AuthenticationTypes.Anonymous; // Noncompliant
var searcher = new DirectorySearcher(entry);

// Noncompliant: No credentials provided
var entry = new DirectoryEntry("LDAP://myserver"); // Noncompliant
var searcher = new DirectorySearcher(entry);

compliant:
// Compliant: Using secure authentication
var entry = new DirectoryEntry("LDAP://myserver", username, password);
entry.AuthenticationType = AuthenticationTypes.Secure; // Compliant
var searcher = new DirectorySearcher(entry);

// Compliant: Using encryption
var entry = new DirectoryEntry("LDAP://myserver", username, password);
entry.AuthenticationType = AuthenticationTypes.Encryption; // Compliant
var searcher = new DirectorySearcher(entry);
